USE worship_db;

INSERT INTO songs (song_number, title, artist, composer, language, lyrics_original, chords, original_key, capo, bpm, time_signature, structure, created_by, is_active) VALUES
(46, 'Build My Life', 'Housefires', 'Brett Younker, Karl Martin, Kirby Kaple, Matt Redman, Pat Barrett', 'english',
'[Verse 1]\nWorthy of every song we could ever sing\nWorthy of all the praise we could ever bring\nWorthy of every breath we could ever breathe\nWe live for You\n\n[Verse 2]\nJesus the name above every other name\nJesus the only one who could ever save\nWorthy of every breath we could ever breathe\nWe live for You\n\n[Chorus]\nHoly there is no one like You\nThere is none beside You\nOpen up my eyes in wonder\nAnd show me who You are\nAnd fill me with Your heart\nAnd lead me in Your love to those around me\n\n[Bridge]\nI will build my life upon Your love\nIt is a firm foundation\nI will put my trust in You alone\nAnd I will not be shaken',
'[Verse 1]\n[G]Worthy of every song we could [D]ever sing\n[Am]Worthy of all the praise we could [C]ever bring\n[G]Worthy of every breath we could [D]ever breathe\n[Am]We live for [C]You\n\n[Verse 2]\n[G]Jesus the name above every [D]other name\n[Am]Jesus the only one who could [C]ever save\n[G]Worthy of every breath we could [D]ever breathe\n[Am]We live for [C]You\n\n[Chorus]\n[G]Holy there is no one like [D]You\n[Am]There is none be[C]side You\n[G]Open up my eyes in [D]wonder\n[Am]And show me who You [C]are\n[G]And fill me with Your [D]heart\n[Am]And lead me in Your love to those a[C]round me\n\n[Bridge]\n[G]I will build my life upon Your [D]love\nIt is a firm foun[Am]dation\n[G]I will put my trust in [D]You alone\n[Am]And I will not be [C]shaken',
'G', 0, 71, '4/4', 'Verse1, Verse2, Chorus, Bridge', 1, TRUE),

(47, 'Reckless Love', 'Cory Asbury', 'Cory Asbury, Caleb Culver, Ran Jackson', 'english',
'[Verse 1]\nBefore I spoke a word You were singing over me\nYou have been so so good to me\nBefore I took a breath You breathed Your life in me\nYou have been so so kind to me\n\n[Chorus]\nOh the overwhelming never-ending reckless love of God\nOh it chases me down fights till I''m found\nLeaves the ninety-nine\nI couldn''t earn it I don''t deserve it\nStill You give Yourself away\nOh the overwhelming never-ending reckless love of God\n\n[Verse 2]\nWhen I was Your foe still Your love fought for me\nYou have been so so good to me\nWhen I felt no worth You paid it all for me\nYou have been so so kind to me',
'[Verse 1]\n[G]Before I spoke a word You were [D]singing over me\n[Em]You have been so so [C]good to me\n[G]Before I took a breath You breathed Your [D]life in me\n[Em]You have been so so [C]kind to me\n\n[Chorus]\n[G]Oh the overwhelming never-ending reckless love of [D]God\n[Em]Oh it chases me down fights till I''m [C]found\nLeaves the [G]ninety-nine\n[D]I couldn''t earn it I don''t deserve it\n[Em]Still You give Your[C]self away\n[G]Oh the overwhelming never-ending reckless love of [D]God [Em] [C]\n\n[Verse 2]\n[G]When I was Your foe still Your [D]love fought for me\n[Em]You have been so so [C]good to me\n[G]When I felt no worth You paid it [D]all for me\n[Em]You have been so so [C]kind to me',
'G', 0, 71, '4/4', 'Verse1, Chorus, Verse2, Chorus', 1, TRUE),

(48, 'Do It Again', 'Elevation Worship', 'Chris Brown, Mack Brock, Matt Brock, Steven Furtick', 'english',
'[Verse 1]\nWalking around these walls\nI thought by now they''d fall\nBut You have never failed me yet\nWaiting for change to come\nKnowing the battle''s won\nFor You have never failed me yet\n\n[Chorus]\nYour promise still stands\nGreat is Your faithfulness faithfulness\nI''m still in Your hands\nThis is my confidence You''ve never failed me yet\n\n[Bridge]\nI''ve seen You move You move the mountains\nAnd I believe I''ll see You do it again\nYou made a way where there was no way\nAnd I believe I''ll see You do it again',
'[Verse 1]\n[D]Walking around these [A]walls\n[Bm]I thought by now they''d [G]fall\n[D]But You have never [A]failed me [G]yet\n[D]Waiting for change to [A]come\n[Bm]Knowing the battle''s [G]won\n[D]For You have never [A]failed me [G]yet\n\n[Chorus]\n[G]Your promise still [D]stands\n[A]Great is Your faithfulness faith[Bm]fulness\n[G]I''m still in Your [D]hands\nThis is my [A]confidence You''ve never [G]failed me yet\n\n[Bridge]\n[Bm]I''ve seen You move You move the [G]mountains\n[D]And I believe I''ll see You [A]do it again\n[Bm]You made a way where there was [G]no way\n[D]And I believe I''ll see You [A]do it again [D]',
'D', 0, 68, '4/4', 'Verse1, Chorus, Bridge, Chorus', 1, TRUE),

(49, 'Great Are You Lord', 'All Sons and Daughters', 'Jason Ingram, David Leonard, Leslie Jordan', 'english',
'[Verse 1]\nYou give life You are love\nYou bring light to the darkness\nYou give hope You restore every heart that is broken\nGreat are You Lord\n\n[Chorus]\nIt''s Your breath in our lungs\nSo we pour out our praise we pour out our praise\nIt''s Your breath in our lungs\nSo we pour out our praise to You only\n\n[Bridge]\nAll the earth will shout Your praise\nOur hearts will cry these bones will sing\nGreat are You Lord',
'[Verse 1]\n[G]You give life You are [C]love\n[G]You bring light to the [C]darkness\n[G]You give hope You restore every [Am]heart that is broken\n[C]Great are You [G]Lord\n\n[Chorus]\n[C]It''s Your breath in our [G]lungs\nSo we [D]pour out our praise we [Em]pour out our praise\n[C]It''s Your breath in our [G]lungs\nSo we [D]pour out our praise to [G]You only\n\n[Bridge]\n[Em]All the earth will shout Your [C]praise\n[G]Our hearts will cry these [D]bones will sing\n[Em]Great are You [C]Lord [G] [D]',
'G', 0, 67, '4/4', 'Verse1, Chorus, Bridge, Chorus', 1, TRUE),

(50, 'Good Good Father', 'Chris Tomlin', 'Pat Barrett, Anthony Brown', 'english',
'[Verse 1]\nI''ve heard a thousand stories of what they think You''re like\nBut I''ve heard the tender whisper of love in the dead of night\nAnd You tell me that You''re pleased and that I''m never alone\n\n[Chorus]\nYou''re a good good Father\nIt''s who You are it''s who You are it''s who You are\nAnd I''m loved by You\nIt''s who I am it''s who I am it''s who I am\n\n[Verse 2]\nI''ve seen many searching for answers far and wide\nBut I know we''re all searching\nFor answers only You provide\n''Cause You know just what we need\nBefore we say a word',
'[Verse 1]\n[G]I''ve heard a thousand stories of [D]what they think You''re like\n[Em]But I''ve heard the tender whisper of [C]love in the dead of night\n[G]And You tell me that You''re pleased and that I''m [D]never alone [C]\n\n[Chorus]\n[G]You''re a good good [D]Father\n[Em]It''s who You are it''s who You are it''s who You [C]are\n[G]And I''m loved by [D]You\n[Em]It''s who I am it''s who I am it''s who I [C]am\n\n[Verse 2]\n[G]I''ve seen many searching for answers [D]far and wide\n[Em]But I know we''re all searching\n[C]For answers only You provide\n[G]''Cause You know just what we [D]need\nBefore we say a [C]word',
'G', 0, 68, '4/4', 'Verse1, Chorus, Verse2, Chorus', 1, TRUE),

(51, 'Way Maker (Acoustic)', 'Leeland', 'Osinachi Kalu Okoro Egbu', 'english',
'[Verse 1]\nYou are here moving in our midst\nI worship You I worship You\nYou are here working in this place\nI worship You I worship You\n\n[Chorus]\nWay Maker Miracle Worker Promise Keeper\nLight in the darkness my God that is who You are\n\n[Bridge]\nEven when I don''t see it You''re working\nEven when I don''t feel it You''re working\nYou never stop never stop working',
'[Verse 1]\n[G]You are here moving in our [D]midst\n[Em]I worship You I wor[C]ship You\n[G]You are here working in this [D]place\n[Em]I worship You I wor[C]ship You\n\n[Chorus]\n[G]Way Maker Miracle Worker [D]Promise Keeper\n[Em]Light in the darkness my [C]God that is who You are [G]\n\n[Bridge]\n[Em]Even when I don''t see it You''re [C]working\n[G]Even when I don''t feel it You''re [D]working\n[Em]You never stop never [C]stop working [G]',
'G', 2, 68, '4/4', 'Verse1, Chorus, Bridge, Chorus', 1, TRUE),

(52, 'Lion And The Lamb', 'Bethel Music', 'Brenton Brown, Brian Johnson, Leeland Mooring', 'english',
'[Verse 1]\nHe''s coming on the clouds\nKings and kingdoms will bow down\nAnd every chain will break\nAs broken hearts declare His praise\nFor who can stop the Lord Almighty\n\n[Chorus]\nOur God is the Lion the Lion of Judah\nHe''s roaring with power and fighting our battles\nAnd every knee will bow before Him\nOur God is the Lamb the Lamb that was slain\nFor the sin of the world His blood breaks the chains\nAnd every knee will bow before the Lion and the Lamb',
'[Verse 1]\n[G]He''s coming on the [D]clouds\n[Em]Kings and kingdoms will [C]bow down\n[G]And every chain will [D]break\n[Em]As broken hearts declare His [C]praise\n[G]For who can stop the [D]Lord Al[C]mighty\n\n[Chorus]\n[G]Our God is the Lion the [D]Lion of Judah\n[Em]He''s roaring with power and [C]fighting our battles\n[G]And every knee will [D]bow before [Em]Him [C]\n[G]Our God is the Lamb the [D]Lamb that was slain\n[Em]For the sin of the world His [C]blood breaks the chains\n[G]And every knee will bow before the [D]Lion and the [Em]Lamb [C]',
'G', 0, 80, '4/4', 'Verse1, Chorus', 1, TRUE),

(53, 'Death Was Arrested', 'North Point Worship', 'Adam Kersh, Brandon Coker, Heath Balltzglier, Paul Taylor Smith', 'english',
'[Verse 1]\nAlone in my sorrow and dead in my sin\nLost without hope with no place to begin\nYour love made a way to let mercy come in\nWhen death was arrested and my life began\n\n[Chorus]\nAh your grace so free\nWashes over me\nYou have made me new\nNow life begins with You\nIt''s your endless love\nPouring down on us\nYou have made us new\nNow life begins with You',
'[Verse 1]\n[G]Alone in my sorrow and [D]dead in my sin\n[Em]Lost without hope with no [C]place to begin\n[G]Your love made a way to let [D]mercy come in\n[Em]When death was arrested and my [C]life began\n\n[Chorus]\n[G]Ah your grace so [D]free\n[Em]Washes over [C]me\n[G]You have made me [D]new\n[Em]Now life begins with [C]You\n[G]It''s your endless [D]love\n[Em]Pouring down on [C]us\n[G]You have made us [D]new\n[Em]Now life begins with [C]You [G]',
'G', 0, 72, '4/4', 'Verse1, Chorus', 1, TRUE),

(54, 'Raise A Hallelujah', 'Bethel Music', 'Jonathan David Helser, Melissa Helser, Molly Skaggs, Jake Stevens', 'english',
'[Verse 1]\nI raise a hallelujah in the presence of my enemies\nI raise a hallelujah louder than the unbelief\nI raise a hallelujah my weapon is a melody\nI raise a hallelujah heaven comes to fight for me\n\n[Chorus]\nI''m gonna sing in the middle of the storm\nLouder and louder you''re gonna hear my praises roar\nUp from the ashes hope will arise\nDeath is defeated the King is alive',
'[Verse 1]\n[D]I raise a hallelujah in the [G]presence of my enemies\n[D]I raise a hallelujah louder [A]than the unbelief\n[D]I raise a hallelujah my weapon [G]is a melody\n[D]I raise a hallelujah heaven [A]comes to fight for me\n\n[Chorus]\n[G]I''m gonna sing in the middle [D]of the storm\n[G]Louder and louder you''re gonna [A]hear my praises roar\n[G]Up from the ashes [D]hope will arise\n[G]Death is defeated the [A]King is alive [D]',
'D', 0, 76, '4/4', 'Verse1, Chorus', 1, TRUE),

(55, 'Trust In You', 'Lauren Daigle', 'Lauren Daigle, Michael Farren, Paul Mabury', 'english',
'[Verse 1]\nLetting go of every single dream\nI lay each one down at Your feet\nEvery moment of my wandering\nNever changes what You see\n\n[Verse 2]\nI''ve surrendered every plan I''ve held\nFor safe hands that never fail\nI trust in You I trust in You\n\n[Chorus]\nWhen You don''t move the mountains I''m needing You to move\nWhen You don''t part the waters I wish I could walk through\nWhen You don''t give the answers as I cry out to You\nI will trust I will trust I will trust in You',
'[Verse 1]\n[C]Letting go of every single [G]dream\n[Am]I lay each one down at Your [F]feet\n[C]Every moment of my wan[G]dering\n[Am]Never changes what You [F]see\n\n[Verse 2]\n[C]I''ve surrendered every plan I''ve [G]held\n[Am]For safe hands that never [F]fail\n[C]I trust in You I trust in [G]You [F]\n\n[Chorus]\n[Am]When You don''t move the mountains I''m needing [F]You to move\n[C]When You don''t part the waters I wish I could [G]walk through\n[Am]When You don''t give the answers as I [F]cry out to You\n[C]I will trust I will trust I will [G]trust in You [C]',
'C', 0, 67, '4/4', 'Verse1, Verse2, Chorus', 1, TRUE);

